def solve(points: Array[Array[Long]]): Long = {
  val MOD = 1000000007L
  val yToXs = mutable.HashMap.empty[Long, mutable.ArrayBuffer[Long]]

  for (point <- points) {
    val x = point(0)
    val y = point(1)
    yToXs.getOrElseUpdate(y, mutable.ArrayBuffer.empty) += x
  }

  // Filter ys that have at least two points
  val ys = yToXs.filter(_._2.size >= 2).toArray

  var total = 0L

  for (i <- ys.indices) {
    val (y1, xs1) = ys(i)
    val sortedXs1 = xs1.sorted
    val n1 = sortedXs1.size

    for (j <- i + 1 until ys.size) {
      val (y2, xs2) = ys(j)
      val sortedXs2 = xs2.sorted
      val n2 = sortedXs2.size

      // Find common x values between the two y-lines
      val commonXs = mutable.ArrayBuffer.empty[Long]
      var p1 = 0
      var p2 = 0

      while (p1 < n1 && p2 < n2) {
        val x1 = sortedXs1(p1)
        val x2 = sortedXs2(p2)
        if (x1 == x2) {
          commonXs += x1
          p1 += 1
          p2 += 1
        } else if (x1 < x2) {
          p1 += 1
        } else {
          p2 += 1
        }
      }

      val k = commonXs.size
      if (k >= 2) {
        // The number of ways to choose two common x's is C(k, 2)
        // The number of ways to choose other two points is C(n1 - 2, 0) + ... but no, it's (n1 - k) * (n2 - k)
        // Wait, no. The two common x's are fixed, so the other two points must be non-common x's in both lines.
        // So for each line, we have (number of non-common x's) = (n1 - k) and (n2 - k)
        // The total combinations for this pair of y-lines is C(k, 2) * (n1 - k) * (n2 - k)
        val ck2 = k.toLong * (k - 1) / 2
        val other = (n1 - k).toLong * (n2 - k).toLong
        total = (total + ck2 * other) % MOD
      }
    }
  }

  total
}
