def solve(points: Array[Array[Long]]): Long = {
  val MOD = 1000000007L
  val yToXs = mutable.HashMap.empty[Long, mutable.ArrayBuffer[Long]]

  for (point <- points) {
    val x = point(0)
    val y = point(1)
    yToXs.getOrElseUpdate(y, mutable.ArrayBuffer.empty) += x
  }

  val yPairs = mutable.ArrayBuffer.empty[(Long, Long)]
  val ys = yToXs.keys.toArray.sorted

  for (i <- 0 until ys.length) {
    for (j <- i + 1 until ys.length) {
      val y1 = ys(i)
      val y2 = ys(j)
      if (yToXs(y1).length >= 2 && yToXs(y2).length >= 2) {
        yPairs += ((y1, y2))
      }
    }
  }

  var count = 0L
  val lineCount = mutable.HashMap.empty[(Long, Long), Long]

  for ((y1, y2) <- yPairs) {
    val xs1 = yToXs(y1).sorted
    val xs2 = yToXs(y2).sorted

    if (xs1.length >= 2 && xs2.length >= 2) {
      val x1Diff = xs1(1) - xs1(0)
      val x2Diff = xs2(1) - xs2(0)
      val gcdVal = gcd(x1Diff, x2Diff)
      val reduced = (x1Diff / gcdVal, x2Diff / gcdVal)

      lineCount(reduced) = lineCount.getOrElse(reduced, 0L) + 1L
    }
  }

  for ((_, cnt) <- lineCount) {
    count = (count + cnt * (cnt - 1) / 2) % MOD
  }

  count
}

def gcd(a: Long, b: Long): Long = {
  if (b == 0) a else gcd(b, a % b)
}
