import scala.collection.mutable

def solve(points: Array[Array[Long]]): Long = {
  val MOD = 1000000007L
  val yToXs = mutable.HashMap.empty[Long, mutable.ArrayBuffer[Long]]

  for (point <- points) {
    val y = point(1)
    val x = point(0)
    yToXs.getOrElseUpdate(y, mutable.ArrayBuffer.empty) += x
  }

  val yPairs = yToXs.keys.toArray.sorted
  var res = 0L

  for (i <- 0 until yPairs.length) {
    for (j <- i + 1 until yPairs.length) {
      val y1 = yPairs(i)
      val y2 = yPairs(j)
      val xs1 = yToXs(y1).sorted
      val xs2 = yToXs(y2).sorted

      var left1 = 0
      var left2 = 0
      var right1 = 0
      var right2 = 0

      while (left1 < xs1.length && left2 < xs2.length) {
        if (xs1(left1) == xs2(left2)) {
          left1 += 1
          left2 += 1
        } else if (xs1(left1) < xs2(left2)) {
          left1 += 1
        } else {
          left2 += 1
        }
      }

      right1 = xs1.length - 1
      right2 = xs2.length - 1

      while (right1 >= 0 && right2 >= 0) {
        if (xs1(right1) == xs2(right2)) {
          right1 -= 1
          right2 -= 1
        } else if (xs1(right1) > xs2(right2)) {
          right1 -= 1
        } else {
          right2 -= 1
        }
      }

      val commonLeft = left1
      val commonRight = xs1.length - 1 - right1
      val common = commonLeft + commonRight
      val m = xs1.length - common
      val n = xs2.length - common

      res = (res + m.toLong * n.toLong) % MOD
    }
  }

  res
}
